const t = $input.first().json;
let msg = t.data?.content || t.data?.text || '';
const orig = msg;
const phoneMap = [], nameMap = [];
const sd = $getWorkflowStaticData('global');
const spaId = sd.spaId || 'default-spa';
msg = msg.replace(/\b(0[35789]\d{8})\b/g, (m) => { const id = phoneMap.length; phoneMap.push({mask:'[PHONE_'+id+']',real:m}); return phoneMap[id].mask; });
msg = msg.replace(/\b(?:tên|Tôi là|Em là|Anh là|Chị là)\s+([A-ZÀ-Ỹ][a-zà-ỹ]{1,15})\b/gi, (f,n) => { const id = nameMap.length; const ph='[NAME_'+id+']'; nameMap.push({mask:ph,real:n}); return f.replace(n,ph); });
return [{json:{originalMessage:orig,maskedMessage:msg,phoneMap,nameMap,senderId:t.data?.fromId||t.data?.senderId||'unknown',senderName:t.data?.senderName||'Khách hàng',threadId:t.threadId||'',spaId}}];

const pii = $('Code - PII Masking').first().json;
const svcRows = $('DT - Get Services').all();
const cfgRows = $('DT - Get Config').all();
const spaRow = $('DT - Get Spa Info').first();
let priceText = svcRows.map(r => '- ' + r.json.name + ': ' + (r.json.price||0) + 'đ').join('\n') || '(Chưa có giá)';
let cfg = {};
cfgRows.forEach(r => { cfg[r.json.key] = r.json.value; });
const si = spaRow ? spaRow.json : {};
return [{json:{
  priceSection: priceText,
  spaInfo: { tenChiNhanh: si.name||'Spa', diaChi: si.address||'[Chưa cập nhật]', gioHoatDong: si.open_hours||((cfg.open_time||'08:00')+'-'+(cfg.close_time||'20:00')), ngayHoatDong: si.active_days||'T2-CN' },
  customerMessage: pii.originalMessage, maskedMessage: pii.maskedMessage,
  phoneMap: pii.phoneMap, nameMap: pii.nameMap, originalMessage: pii.originalMessage,
  senderId: pii.senderId, senderName: pii.senderName, threadId: pii.threadId, spaId: pii.spaId
}}];

const input = $input.first().json;
const msg = (input.customerMessage || '').toLowerCase();
const detected = {};
const svcM = msg.match(/(?:làm tóc|làm nail|chăm sóc da|massage|uốn|nhuộm|cắt|gội)/i);
if (svcM) detected.service = svcM[0];
const timeM = msg.match(/(sáng|chiều|tối|thứ [2-7]|ngày mai|\d{1,2}[h:]\d{0,2})/i);
if (timeM) detected.time = timeM[0];
const nameM = msg.match(/(?:tên|em là|anh là|chị là)\s+([a-zà-ỹ]{2,20})\b/i);
if (nameM) detected.name = nameM[1];
const phoneM = msg.match(/\b0[35789]\d{8}\b/);
if (phoneM) detected.phone = phoneM[0];
const hasBooking = /đặt|book|lịch|muốn làm/i.test(msg);
const hasNew = !!(detected.service||detected.name||detected.phone);
const isTopic = /giờ|địa chỉ|ở đâu|bao nhiêu/i.test(msg) && !hasBooking && !hasNew;
let inst = isTopic ? '\n[HỆ THỐNG: Trả lời câu hỏi, rồi hỏi đặt lịch]' : '\n[HỆ THỐNG: Thu thập: dịch vụ -> tên -> SĐT]\n[Khi đủ, xuất JSON: {"booking":true,"name":"...","phone":"...","service":"...","note":"..."}]';
return [{json:{...input,currentDetected:detected,isTopicChange:isTopic,systemInstruction:inst}}];

