const input = $input.first().json;
const msg = (input.originalMessage || input.customerMessage || '').toLowerCase();
const P = {human:/gọi cho em|cho số dt|liên hệ trực tiếp/i,complaint:/nói chuyện với quản lý|không hài lòng|phản ánh|tệ quá/i,distrust:/không tin bot|người thật|talk to human/i};
let escType = null;
for (const [t,re] of Object.entries(P)) { if(re.test(msg)){escType=t;break;} }
let ownerAlert=null,escReply=null;
if(escType==='human'){ownerAlert='KHÁCH MUỐN NÓI CHUYỆN TRỰC TIẾP\nSender: '+input.senderId;escReply='Dạ em cho nhân viên liên hệ ngay! 📞';}
else if(escType==='complaint'){ownerAlert='🔴 LEAD NÓNG\nSender: '+input.senderId;escReply='Em xin lỗi! Để em kết nối quản lý!';}
else if(escType==='distrust'){escReply='Dạ em là nhân viên tư vấn online! Em gửi hotline nhé!';}
return [{json:{...input,isEscalation:!!escType,escalationType:escType,ownerAlert,escalationReply:escReply}}];

const input=$input.first().json;
const sId=input.senderId||'unknown';const sName=input.senderName||'Khách hàng';
const custMsg=input.originalMessage||input.customerMessage||'';
const thId=input.threadId||'';
const spaId=$getWorkflowStaticData('global').spaId||'default-spa';
const ts=new Date().toLocaleString('vi-VN',{timeZone:'Asia/Ho_Chi_Minh'});
const ai=input.output||'';
if(!ai||input.error)return [{json:{isBooking:false,bookingData:null,replyText:'Dạ em đang bận. Anh/chị để lại số DT, em gọi lại! 💖',senderId:sId,senderName:sName,rawAiOutput:ai,threadId:thId,spaId,isError:true,messageType:'Fallback',customerMessage:custMsg,timestamp:ts}}];
let isBk=false,bkData=null,reply='';
try{const m=ai.match(/\{[\s\S]*"booking"[\s\S]*\}/);
if(m){const p=JSON.parse(m[0]);if(p.booking===true&&p.phone){isBk=true;bkData={name:p.name||'Không rõ',phone:p.phone,service:p.service||'Không rõ',note:p.note||'',timestamp:ts};reply='✅ Em đã ghi nhận lịch của '+bkData.name+'!\nDịch vụ: '+bkData.service+'\nEm sẽ liên hệ xác nhận. 💖';}}}catch(e){isBk=false;}
if(!isBk)reply=ai;
let mt='Tư vấn';if(isBk)mt='Đặt lịch';else{const l=custMsg.toLowerCase();if(l.match(/giá|bao nhiêu/))mt='Hỏi giá';else if(l.match(/phản ánh|tệ/))mt='Phản ánh';else if(l.match(/giờ|địa chỉ/))mt='Hỏi thông tin';}
return [{json:{isBooking:isBk,bookingData:bkData,replyText:reply,senderId:sId,senderName:sName,rawAiOutput:ai,threadId:thId,spaId,isError:false,messageType:mt,customerMessage:custMsg,timestamp:ts}}];

const data=$input.first().json;
let r=data.replyText||'';
(data.phoneMap||[]).forEach(e=>{const esc=e.mask.replace(/[[\]]/g,'\\$&');r=r.replace(new RegExp(esc,'g'),e.real);});
(data.nameMap||[]).forEach(e=>{const esc=e.mask.replace(/[[\]]/g,'\\$&');r=r.replace(new RegExp(esc,'g'),e.real);});
return [{json:{...data,replyText:r}}];

const ex=$input.all();
const parse=$('Parse Booking').first().json;
const unmask=$('Code - Unmask Reply').first().json;
const now=new Date().toISOString();
if(ex.length===0||!ex[0].json.id){
  return [{json:{...unmask,duplicateAction:'insert',bookingData:parse.bookingData,duplicateReply:'',created_at:now,updated_at:now}}];
}
let action='insert',reply='';
const st=ex[0].json.status||'';
if(st==='Mới đặt'){action='update';reply='Em đã cập nhật lịch! 💖';}
else if(st==='Đã xác nhận'){action='reject';reply='Lịch đã xác nhận! Gọi hotline 📞';}
else if(st==='Hoàn thành'){action='insert';}
return [{json:{...unmask,duplicateAction:action,bookingData:parse.bookingData,duplicateReply:reply,created_at:ex[0].json.created_at||now,updated_at:now}}];

const d=$input.first().json;const b=d.bookingData||{};
const reply='Dạ em đã ghi nhận! ✅\nDịch vụ: '+(b.service||'Chưa rõ')+'\nEm xác nhận lại sáng mai 8h. 💖';
return [{json:{...d,replyText:reply,threadId:d.threadId||''}}];

const d=$input.first().json;const b=d.bookingData;
const msg='🔔 KHÁCH ĐẶT LỊCH
👤 '+b.name+'
📞 '+b.phone+'
💇 '+b.service+'
📝 '+(b.note||'Không có')+'
⏰ '+b.timestamp;
return [{json:{ownerMessage:msg,threadId:d.threadId}}];

const unmask = $('Code - Unmask Reply').first().json;
const smartCol = $('Code - Smart Collection').first().json;
const trigger = $('Zalo Message Trigger').first().json;
return [{json:{
  spa_id: unmask.spaId || 'default-spa',
  zalo_id: unmask.senderId || 'unknown',
  customer_name: unmask.senderName || 'Khách hàng',
  customer_message_masked: smartCol.maskedMessage || '',
  ai_reply: unmask.replyText || '',
  category: unmask.messageType || 'Tư vấn',
  is_booking: unmask.isBooking ? 'true' : 'false',
  session_id: trigger.data?.fromId || 'default'
}}];
